$adminCred = Get-Credential -Message "Geef administrator credentials"

$users = @(
    @{Name="student1"; Password="P@ssword123"},
    @{Name="student2"; Password="P@ssword123"}
)

foreach ($user in $users) {
    $username = $user.Name
    $plainPassword = $user.Password
    $securePassword = ConvertTo-SecureString $plainPassword -AsPlainText -Force

    Invoke-Command -ComputerName "localhost" -Credential $adminCred -ScriptBlock {
        param($username, $securePassword)
        if (Get-LocalUser -Name $username -ErrorAction SilentlyContinue) {
            Write-Output "Gebruiker $username bestaat al"
        } else {
            New-LocalUser -Name $username -Password $securePassword -FullName $username -Description "Aangemaakt via script"
            Add-LocalGroupMember -Group "Users" -Member $username
            Write-Output "Gebruiker $username aangemaakt"
        }
    } -ArgumentList $username, $securePassword
}

