function ToonSID {
    $aantalGebruikers = (Get-LocalUser).Count
    do {
        [int]$aantal = Read-Host 'Hoeveel SIDs wil je opvragen?'
        if ($aantal -gt $aantalGebruikers) {
            Write-Host "Opgelet: er zijn maar $aantalGebruikers gebruikers actief op dit toestel. Geef een andere waarde op."
        }
    } until ($aantal -le $aantalGebruikers)

    for ($i = 0; $i -lt $aantal; $i++) {
        do {
            $naam = Read-Host 'Geef een geldige gebruikersnaam op'
            $gebruiker = Get-LocalUser -Name $naam -ErrorAction SilentlyContinue
            if (-not $gebruiker) { Write-Host 'Gebruikersnaam bestaat niet' }
        } until ($gebruiker)
        Write-Host "SID van $naam: $([string]$gebruiker.SID)"
    }
}
