$BasePath = "C:\Company\Projects"
$Projects = @("Project_Alpha", "Project_Beta", "Project_Gamma")
$ArchivedProjects = @("Project_Beta")
$RemoveProjects = @("Project_Test", "Project_Old")
$SubFolders = @("Docs","Scripts","Archive","Logs")

if (!(Test-Path -Path $BasePath)) {
    New-Item -ItemType Directory -Path $BasePath
    Write-Host "Basispad aangemaakt:" $BasePath
} else {
    Write-Host "Basispad bestaat al:" $BasePath
}

foreach ($project in $Projects) {
    $projectPath = Join-Path $BasePath $project
    if (!(Test-Path -Path $projectPath)) {
        New-Item -ItemType Directory -Path $projectPath
        Write-Host "Projectmap aangemaakt:" $project
    } else {
        Write-Host "Projectmap bestaat al:" $project
    }
    foreach ($sub in $SubFolders) {
        $subPath = Join-Path $projectPath $sub
        if (!(Test-Path -Path $subPath)) {
            New-Item -ItemType Directory -Path $subPath
            Write-Host "  Submap aangemaakt:" $sub
        } else {
            Write-Host "  Submap bestaat al:" $sub
        }
    }
}

foreach ($archived in $ArchivedProjects) {
    $oldPath = Join-Path $BasePath $archived
    $newPath = Join-Path $BasePath ($archived + "_ARCHIVED")
    if (Test-Path -Path $oldPath) {
        if (!(Test-Path -Path $newPath)) {
            Rename-Item -Path $oldPath -NewName ($archived + "_ARCHIVED")
            Write-Host "Project gearchiveerd:" $archived
        } else {
            Write-Host "Gearchiveerde map bestaat al:" $newPath
        }
    } else {
        Write-Host "Projectmap niet gevonden voor archivering:" $archived
    }
}

foreach ($remove in $RemoveProjects) {
    $removePath = Join-Path $BasePath $remove
    if (Test-Path -Path $removePath) {
        Remove-Item -Path $removePath -Recurse -Force
        Write-Host "Project verwijderd:" $remove
    } else {
        Write-Host "Project niet gevonden voor verwijdering:" $remove
    }
}

Write-Host "Projectbeheer script uitgevoerd."

while ($true) {
    Write-Host "1. Lijst alle gebruikersaccounts"
    Write-Host "2. Toon details van een specifiek gebruikersaccount"
    Write-Host "3. Verwijder een gebruikersaccount"
    Write-Host "4. Exit"
    $choice = Read-Host "Kies een optie"

    switch ($choice) {
        "1" {
            Get-CimInstance Win32_UserAccount | Select-Object Name, Description | Format-Table
        }
        "2" {
            $name = Read-Host "Geef de gebruikersnaam in"
            $user = Get-CimInstance Win32_UserAccount | Where-Object { $_.Name -eq $name }
            if ($user) {
                Write-Host "Naam:        $($user.Name)"
                Write-Host "Beschrijving: $($user.Description)"
                Write-Host "AccountType: $($user.AccountType)"
                Write-Host "Disabled:    $($user.Disabled)"
            } else {
                Write-Host "Gebruiker niet gevonden."
            }
        }
        "3" {
            $disabled = Get-CimInstance Win32_UserAccount | Where-Object { $_.Disabled -eq $true }
            foreach ($u in $disabled) {
                Remove-LocalUser -Name $u.Name
                Write-Host "Verwijderd: $($u.Name)"
            }
        }
        "4" { break }
        default { Write-Host "Ongeldige keuze." }
    }
    if ($choice -eq "4") { break }
}

$eersteGetal = Read-Host 'Voer het eerste getal in'
$secondGetal = Read-Host 'Voer het tweede getal in'
$bewerking = Read-Host 'Kies een bewerking: (+) optellen, (-) aftrekken, (*) vermenigvuldigen, (/) delen'

$eersteGetal = [decimal]$eersteGetal
$secondGetal = [decimal]$secondGetal

if ($bewerking -eq '+') {
    $resultaat = $eersteGetal + $secondGetal
    Write-Host "Resultaat: $eersteGetal + $secondGetal = $resultaat"
} elseif ($bewerking -eq '-') {
    $resultaat = $eersteGetal - $secondGetal
    Write-Host "Resultaat: $eersteGetal - $secondGetal = $resultaat"
} elseif ($bewerking -eq '*') {
    $resultaat = $eersteGetal * $secondGetal
    Write-Host "Resultaat: $eersteGetal * $secondGetal = $resultaat"
} elseif ($bewerking -eq '/') {
    if ($secondGetal -eq 0) {
        Write-Host 'Fout: Delen door nul is niet mogelijk!'
    } else {
        $resultaat = $eersteGetal / $secondGetal
        Write-Host "Resultaat: $eersteGetal / $secondGetal = $resultaat"
    }
} else {
    Write-Host 'Ongeldige bewerking gekozen. Kies (+), (-), (*), of (/).'
}

$password = Read-Host 'Voer een wachtwoord in'

while ($true) {
    if ($password.Length -lt 8) {
        Write-Host 'Het wachtwoord is te kort (minder dan 8 tekens). Probeer opnieuw.'
        $password = Read-Host 'Voer een nieuw wachtwoord in'
        continue
    }

    if ($password -notmatch '\d') {
        Write-Host 'Het wachtwoord bevat geen cijfers. Probeer opnieuw.'
        $password = Read-Host 'Voer een nieuw wachtwoord in'
        continue
    }

    if ($password -notmatch '[^a-zA-Z0-9]') {
        Write-Host 'Het wachtwoord bevat geen speciale tekens. Probeer opnieuw.'
        $password = Read-Host 'Voer een nieuw wachtwoord in'
        continue
    }

    Write-Host 'De sterkte van het wachtwoord is: sterk'
    break
}

