$disks = Get-PSDrive -PSProvider FileSystem | Where-Object { $_.Used -gt 0 }

foreach ($disk in $disks) {
    $freeGB = [math]::Round($disk.Free / 1GB, 2)
    $totalGB = [math]::Round($disk.Used / 1GB + $freeGB, 2)
    $percentageFree = ($freeGB / $totalGB) * 100

    Write-Host "$($disk.Name): Vrije ruimte: $freeGB GB ($([math]::Round($percentageFree, 2))%)"

    if ($percentageFree -lt 10) {
        Write-Host "WAARSCHUWING: Schijf $($disk.Name) heeft minder dan 10% vrije ruimte!" -ForegroundColor Red
        Add-Content -Path 'disk_space_log.txt' -Value "$(Get-Date): $($disk.Name) heeft minder dan 10% vrije ruimte."
    }
}

