    Write-Host 'Basispad aangemaakt.'
} else {
    Write-Host 'Basispad bestaat al.'
}

# Stap 2 & 3: projectmappen + submappen
foreach ($project in $Projects) {
    $projectPath = "$BasePath\$project"
    if (!(Test-Path $projectPath)) {
        New-Item -ItemType Directory -Path $projectPath | Out-Null
        Write-Host "Map $project aangemaakt."
    } else {
        Write-Host "Map $project bestaat al."
    }

    foreach ($sub in $SubFolders) {
        $subPath = "$projectPath\$sub"
        if (!(Test-Path $subPath)) {
            New-Item -ItemType Directory -Path $subPath | Out-Null
            Write-Host "Submap $sub aangemaakt in $project."
        } else {
            Write-Host "Submap $sub bestaat al in $project."
        }
    }
}

# Stap 4: archiveren
$betaPath = "$BasePath\Project_Beta"
if (Test-Path $betaPath) {
    Rename-Item -Path $betaPath -NewName 'Project_Beta_ARCHIVED'
    Write-Host 'Project_Beta gearchiveerd als Project_Beta_ARCHIVED.'
} else {
    Write-Host 'Project_Beta niet gevonden, archivering overgeslagen.'
}

# Stap 5: opruimen
foreach ($old in @('Project_Test', 'Project_Old')) {
    $oldPath = "$BasePath\$old"
    if (Test-Path $oldPath) {
        Remove-Item -Path $oldPath -Recurse -Force
        Write-Host "$old verwijderd."
    } else {
        Write-Host "$old bestaat niet, niets te verwijderen."
    }
}

# Haal info op over logische schijven
$Disks = Get-WmiObject Win32_LogicalDisk | Where-Object { $_.DriveType -eq 3 } |
    Select-Object DeviceID, FileSystem,
        @{Name='Vrij_MB';Expression={[math]::Round($_.FreeSpace / 1MB, 2)}},
        @{Name='Totaal_MB';Expression={[math]::Round($_.Size / 1MB, 2)}}

# Haal schijfgezondheid op
$Health = Get-WmiObject Win32_DiskDrive | Select-Object Model, Status

# Toon resultaten
foreach ($disk in $Disks) {
    Write-Output "Schijf $($disk.DeviceID) ($($disk.FileSystem)) - Vrij: $($disk.Vrij_MB) MB van $($disk.Totaal_MB) MB"
}
foreach ($hdd in $Health) {
    Write-Output "Schijfmodel: $($hdd.Model) - Status: $($hdd.Status)"
}

# Lijst van te controleren services
$Services = @('wuauserv', 'Spooler', 'WinDefend')

# Controleer de status van elke service
foreach ($service in $Services) {
    $ServiceStatus = Get-WmiObject Win32_Service | Where-Object { $_.Name -eq $service }

    if ($ServiceStatus.State -eq 'Running') {
        Write-Output "Service '$($ServiceStatus.Name)' draait"
    } else {
        Write-Output "Service '$($ServiceStatus.Name)' draait niet - Start service..."
        Start-Service -Name $service
        Write-Output "Service '$service' is gestart"
    }
}

# Controleer het aantal cores en de hoeveelheid RAM met WMI
$cpu = Get-WmiObject Win32_Processor
$ram = Get-WmiObject Win32_ComputerSystem
$disk = Get-WmiObject Win32_LogicalDisk -Filter "DeviceID='C:'"

# Minimale vereisten
$minCores = 4
$minRAM = 16GB
$minDiskSpace = 100GB

$freeDiskSpace = $disk.FreeSpace

if ($cpu.NumberOfCores -ge $minCores -and
    $ram.TotalPhysicalMemory -ge $minRAM -and
    $freeDiskSpace -ge $minDiskSpace) {

    Write-Output 'Systeem voldoet aan de vereisten. Updates worden geïnstalleerd...'

    Install-Module PSWindowsUpdate -Force -SkipPublisherCheck
    Import-Module PSWindowsUpdate
    Get-WindowsUpdate -AcceptAll -Install -AutoReboot

} else {
    Write-Output 'Systeem voldoet niet aan de vereisten:'
    if ($cpu.NumberOfCores -lt $minCores) { Write-Output "- Onvoldoende CPU cores: $($cpu.NumberOfCores) (minimaal $minCores vereist)" }
    if ($ram.TotalPhysicalMemory -lt $minRAM) { Write-Output "- Onvoldoende RAM: $(($ram.TotalPhysicalMemory / 1GB) -as [int]) GB (minimaal 16 GB vereist)" }
    if ($freeDiskSpace -lt $minDiskSpace) { Write-Output "- Onvoldoende vrije schijfruimte: $(($freeDiskSpace / 1GB) -as [int]) GB (minimaal 100 GB vereist)" }
}

# Haal de temperatuur op via WMI
$Temp = Get-WmiObject -Namespace 'root\WMI' -Class MSAcpi_ThermalZoneTemperature | Select-Object CurrentTemperature

# Omrekenen van Kelvin*10 naar Celsius
$CPUtempC = ($Temp.CurrentTemperature / 10) - 273.15

# Controleer of de temperatuur te hoog is
if ($CPUtempC -gt 75) {
    Write-Output "Waarschuwing: CPU-temperatuur is $CPUtempC°C!"
} else {
    Write-Output "Huidige CPU-temperatuur: $CPUtempC°C (Normaal)"
}
